import{_ as a,o as e,c as i,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"迁移指南","description":"","frontmatter":{"read_when":["你正在将 OpenSoul 迁移到新的笔记本电脑/服务器","你想保留会话、认证和渠道登录（WhatsApp 等）"],"summary":"将 OpenSoul 安装从一台机器迁移到另一台","title":"迁移指南","x-i18n":{"generated_at":"2026-02-03T07:49:55Z","model":"claude-opus-4-5","provider":"pi","source_hash":"604d862c4bf86e7924d09028db8cc2514ca6f1d64ebe8bb7d1e2dde57ef70caa","source_path":"install/migrating.md","workflow":15}},"headers":[],"relativePath":"zh-CN/install/migrating.md","filePath":"zh-CN/install/migrating.md","lastUpdated":1771906665000}'),n={name:"zh-CN/install/migrating.md"};function o(t,s,p,d,r,h){return e(),i("div",null,[...s[0]||(s[0]=[l(`<h1 id="将-opensoul-迁移到新机器" tabindex="-1"><a class="header-anchor" href="#将-opensoul-迁移到新机器">#</a> 将 OpenSoul 迁移到新机器</h1><p>本指南将 OpenSoul Gateway 网关从一台机器迁移到另一台，<strong>无需重新进行新手引导</strong>。</p><p>迁移在概念上很简单：</p><ul><li>复制<strong>状态目录</strong>（<code>$OPENSOUL_STATE_DIR</code>，默认：<code>~/.opensoul/</code>）— 这包括配置、认证、会话和渠道状态。</li><li>复制你的<strong>工作区</strong>（默认 <code>~/.opensoul/workspace/</code>）— 这包括你的智能体文件（记忆、提示等）。</li></ul><p>但在<strong>配置文件</strong>、<strong>权限</strong>和<strong>部分复制</strong>方面有常见的陷阱。</p><h2 id="开始之前-你要迁移什么" tabindex="-1"><a class="header-anchor" href="#开始之前-你要迁移什么">#</a> 开始之前（你要迁移什么）</h2><h3 id="_1-确定你的状态目录" tabindex="-1"><a class="header-anchor" href="#_1-确定你的状态目录">#</a> 1）确定你的状态目录</h3><p>大多数安装使用默认值：</p><ul><li><strong>状态目录：</strong> <code>~/.opensoul/</code></li></ul><p>但如果你使用以下方式，可能会不同：</p><ul><li><code>--profile &lt;name&gt;</code>（通常变成 <code>~/.opensoul-&lt;profile&gt;/</code>）</li><li><code>OPENSOUL_STATE_DIR=/some/path</code></li></ul><p>如果你不确定，在<strong>旧</strong>机器上运行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在输出中查找 <code>OPENSOUL_STATE_DIR</code> / profile 的提及。如果你运行多个 Gateway 网关，对每个配置文件重复此操作。</p><h3 id="_2-确定你的工作区" tabindex="-1"><a class="header-anchor" href="#_2-确定你的工作区">#</a> 2）确定你的工作区</h3><p>常见默认值：</p><ul><li><code>~/.opensoul/workspace/</code>（推荐的工作区）</li><li>你创建的自定义文件夹</li></ul><p>你的工作区是 <code>MEMORY.md</code>、<code>USER.md</code> 和 <code>memory/*.md</code> 等文件所在的位置。</p><h3 id="_3-了解你将保留什么" tabindex="-1"><a class="header-anchor" href="#_3-了解你将保留什么">#</a> 3）了解你将保留什么</h3><p>如果你复制<strong>两者</strong>——状态目录和工作区，你将保留：</p><ul><li>Gateway 网关配置（<code>opensoul.json</code>）</li><li>认证配置文件 / API 密钥 / OAuth 令牌</li><li>会话历史 + 智能体状态</li><li>渠道状态（例如 WhatsApp 登录/会话）</li><li>你的工作区文件（记忆、Skills 笔记等）</li></ul><p>如果你<strong>只</strong>复制工作区（例如通过 Git），你<strong>不会</strong>保留：</p><ul><li>会话</li><li>凭证</li><li>渠道登录</li></ul><p>这些存储在 <code>$OPENSOUL_STATE_DIR</code> 下。</p><h2 id="迁移步骤-推荐" tabindex="-1"><a class="header-anchor" href="#迁移步骤-推荐">#</a> 迁移步骤（推荐）</h2><h3 id="步骤-0-—-备份-旧机器" tabindex="-1"><a class="header-anchor" href="#步骤-0-—-备份-旧机器">#</a> 步骤 0 — 备份（旧机器）</h3><p>在<strong>旧</strong>机器上，首先停止 Gateway 网关，这样文件不会在复制过程中发生变化：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>（可选但推荐）归档状态目录和工作区：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 如果你使用配置文件或自定义位置，请调整路径</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -czf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul-state.tgz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .opensoul</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -czf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul-workspace.tgz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .opensoul/workspace</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>如果你有多个配置文件/状态目录（例如 <code>~/.opensoul-main</code>、<code>~/.opensoul-work</code>），分别归档每个。</p><h3 id="步骤-1-—-在新机器上安装-opensoul" tabindex="-1"><a class="header-anchor" href="#步骤-1-—-在新机器上安装-opensoul">#</a> 步骤 1 — 在新机器上安装 OpenSoul</h3><p>在<strong>新</strong>机器上，安装 CLI（如果需要还有 Node）：</p><ul><li>参见：<a href="/docs/install/index">安装</a></li></ul><p>在这个阶段，如果新手引导创建了一个新的 <code>~/.opensoul/</code> 也没关系 — 你将在下一步覆盖它。</p><h3 id="步骤-2-—-将状态目录-工作区复制到新机器" tabindex="-1"><a class="header-anchor" href="#步骤-2-—-将状态目录-工作区复制到新机器">#</a> 步骤 2 — 将状态目录 + 工作区复制到新机器</h3><p>复制<strong>两者</strong>：</p><ul><li><code>$OPENSOUL_STATE_DIR</code>（默认 <code>~/.opensoul/</code>）</li><li>你的工作区（默认 <code>~/.opensoul/workspace/</code>）</li></ul><p>常见方法：</p><ul><li><code>scp</code> 压缩包并解压</li><li>通过 SSH 使用 <code>rsync -a</code></li><li>外部驱动器</li></ul><p>复制后，确保：</p><ul><li>包含了隐藏目录（例如 <code>.opensoul/</code>）</li><li>文件所有权对于运行 Gateway 网关的用户是正确的</li></ul><h3 id="步骤-3-—-运行-doctor-迁移-服务修复" tabindex="-1"><a class="header-anchor" href="#步骤-3-—-运行-doctor-迁移-服务修复">#</a> 步骤 3 — 运行 Doctor（迁移 + 服务修复）</h3><p>在<strong>新</strong>机器上：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Doctor 是&quot;安全可靠&quot;的命令。它修复服务、应用配置迁移，并警告不匹配问题。</p><p>然后：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="常见陷阱-以及如何避免" tabindex="-1"><a class="header-anchor" href="#常见陷阱-以及如何避免">#</a> 常见陷阱（以及如何避免）</h2><h3 id="陷阱-配置文件-状态目录不匹配" tabindex="-1"><a class="header-anchor" href="#陷阱-配置文件-状态目录不匹配">#</a> 陷阱：配置文件/状态目录不匹配</h3><p>如果你在旧 Gateway 网关上使用了配置文件（或 <code>OPENSOUL_STATE_DIR</code>），而新 Gateway 网关使用了不同的配置，你会看到如下症状：</p><ul><li>配置更改不生效</li><li>渠道丢失/已登出</li><li>会话历史为空</li></ul><p>修复：使用你迁移的<strong>相同</strong>配置文件/状态目录运行 Gateway 网关/服务，然后重新运行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="陷阱-只复制-opensoul-json" tabindex="-1"><a class="header-anchor" href="#陷阱-只复制-opensoul-json">#</a> 陷阱：只复制 <code>opensoul.json</code></h3><p><code>opensoul.json</code> 是不够的。许多提供商在以下位置存储状态：</p><ul><li><code>$OPENSOUL_STATE_DIR/credentials/</code></li><li><code>$OPENSOUL_STATE_DIR/agents/&lt;agentId&gt;/...</code></li></ul><p>始终迁移整个 <code>$OPENSOUL_STATE_DIR</code> 文件夹。</p><h3 id="陷阱-权限-所有权" tabindex="-1"><a class="header-anchor" href="#陷阱-权限-所有权">#</a> 陷阱：权限/所有权</h3><p>如果你以 root 身份复制或更改了用户，Gateway 网关可能无法读取凭证/会话。</p><p>修复：确保状态目录 + 工作区由运行 Gateway 网关的用户拥有。</p><h3 id="陷阱-在远程-本地模式之间迁移" tabindex="-1"><a class="header-anchor" href="#陷阱-在远程-本地模式之间迁移">#</a> 陷阱：在远程/本地模式之间迁移</h3><ul><li>如果你的 UI（WebUI/TUI）指向<strong>远程</strong> Gateway 网关，远程主机拥有会话存储 + 工作区。</li><li>迁移你的笔记本电脑不会移动远程 Gateway 网关的状态。</li></ul><p>如果你处于远程模式，请迁移 <strong>Gateway 网关主机</strong>。</p><h3 id="陷阱-备份中的密钥" tabindex="-1"><a class="header-anchor" href="#陷阱-备份中的密钥">#</a> 陷阱：备份中的密钥</h3><p><code>$OPENSOUL_STATE_DIR</code> 包含密钥（API 密钥、OAuth 令牌、WhatsApp 凭证）。将备份视为生产密钥：</p><ul><li>加密存储</li><li>避免通过不安全的渠道共享</li><li>如果怀疑泄露，轮换密钥</li></ul><h2 id="验证检查清单" tabindex="-1"><a class="header-anchor" href="#验证检查清单">#</a> 验证检查清单</h2><p>在新机器上，确认：</p><ul><li><code>opensoul status</code> 显示 Gateway 网关正在运行</li><li>你的渠道仍然连接（例如 WhatsApp 不需要重新配对）</li><li>仪表板打开并显示现有会话</li><li>你的工作区文件（记忆、配置）存在</li></ul><h2 id="相关内容" tabindex="-1"><a class="header-anchor" href="#相关内容">#</a> 相关内容</h2><ul><li><a href="/docs/gateway/doctor">Doctor</a></li><li><a href="/docs/gateway/troubleshooting">Gateway 网关故障排除</a></li><li><a href="/docs/help/faq#where-does-opensoul-store-its-data">OpenSoul 在哪里存储数据？</a></li></ul>`,72)])])}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
